text:
{
  "formal_minutes": {
    "project_code": "PUBLIC_MEETING_SMOKE",
    "meeting_title": "UI Theme Package Release Readiness",
    "participants": [
      "Minjun",
      "Seoyeon",
      "Doyun",
      "Hara"
    ],
    "confirmed_decisions": [
      {
        "topic": "공개 릴리스 목표",
        "decision": "스모크 테스트 통과를 전제로 공개 릴리스 목표 시각은 2026-05-15 15:00 KST이다."
      },
      {
        "topic": "packageName mismatch 대응",
        "decision": "packageName mismatch가 발생하면 먼저 package config를 확인하고, 계약 자체가 잘못된 경우에만 스크립트 검토를 진행한다."
      }
    ],
    "rejected_proposals": [
      {
        "proposal": "smoke-theme-pack.mjs에서 packageName mismatch를 무시하도록 변경하자",
        "result": "거절됨"
      }
    ],
    "internal_stretch_goals": [
      {
        "goal": "2026-05-13 수요일 릴리스",
        "status": "내부 스트레치 목표일 뿐이며 최종 확정 일정이 아님"
      },
      {
        "goal": "README 설치 절차를 2026-05-14 목요일까지 검토",
        "status": "가능하면 진행하는 희망사항이며 담당자와 확정 일정이 없음"
      }
    ],
    "non_decisions": [
      {
        "item": "README 설치 절차 검토",
        "note": "필요성은 언급되었으나 담당자 미정, 확정 의사결정 아님"
      },
      {
        "item": "Hara의 tarball 경로 확인",
        "note": "수행은 예정되었으나 정확한 기한은 설정되지 않음"
      }
    ],
    "risks": [
      {
        "risk": "잘못된 tarball 경로가 릴리스를 지연시킬 수 있음"
      },
      {
        "risk": "README 설치 절차가 오래되어 있으면 릴리스 노트가 사용자를 오도할 수 있음"
      }
    ],
    "open_questions": [
      {
        "question": "최종 릴리스 승인 권한자는 누구인가?"
      },
      {
        "question": "릴리스 노트에 내부 수요일 스트레치 목표를 언급해야 하는가?"
      }
    ]
  },
  "action_items": [
    {
      "owner": "Minjun",
      "task": "스모크 테스트를 재실행하고 결과를 공유한다",
      "due": "2026-05-15 10:00 KST",
      "status": "확정",
      "source_certainty": "confirmed"
    },
    {
      "owner": "Doyun",
      "task": "failure triage note를 action_items.md에 작성한다",
      "due": "2026-05-15 12:00 KST",
      "status": "확정",
      "source_certainty": "confirmed"
    },
    {
      "owner": "Hara",
      "task": "Minjun의 스모크 결과 공유 후 생성된 tarball 경로를 확인한다",
      "due": null,
      "status": "확정, 단 정확한 기한 미설정",
      "source_certainty": "confirmed"
    },
    {
      "owner": null,
      "task": "README 설치 절차를 검토한다",
      "due": "가능하면 2026-05-14 KST",
      "status": "미확정",
      "source_certainty": "suggested_only"
    }
  ],
  "followup_note": {
    "what_to_check_next": [
      "2026-05-15 10:00 KST까지 Minjun의 스모크 테스트 통과 여부와 공유 결과를 확인한다.",
      "스모크 실패 시 Doyun의 triage note 작성 상태를 2026-05-15 12:00 KST 기준으로 확인한다.",
      "Minjun 결과 공유 이후 Hara의 tarball 경로 점검 결과를 확인한다.",
      "README 설치 절차 검토의 담당자 지정 여부와 실제 검토 필요성을 별도로 확인한다.",
      "최종 릴리스 승인 권한자와 릴리스 노트에 수요일 스트레치 목표를 언급할지 여부를 결정해야 한다."
    ],
    "what_not_to_invent": [
      "고객명 또는 외부 파트너",
      "예산 정보",
      "보안 사고",
      "프로덕션 장애",
      "법무 승인 필요 여부",
      "미지정 담당자",
      "명시되지 않은 추가 마감일"
    ]
  },
  "non_invention_rules": [
    "이 출력은 제공된 공개용 합성 회의 메모만 근거로 작성한다.",
    "확정 결정과 제안, 스트레치 목표, 리스크, 미해결 질문을 섞지 않는다.",
    "명시되지 않은 고객, 예산, 보안, 장애, 법무, 담당자, 기한 사실을 추가하지 않는다.",
    "수요일 릴리스는 최종 결정이 아니라 내부 스트레치 목표로만 기록한다.",
    "README 검토는 필요성이 언급되었을 뿐 담당자 미정 상태로 유지한다.",
    "Hara 작업에는 정확한 마감이 없으므로 임의 기한을 넣지 않는다."
  ]
}
